INSERT INTO recipes (id, user_id, title, description, instructions, image_url, servings, source_url, source_name) VALUES ('335ef4f6-6edd-43de-9a18-f1edd321ef3c', 'admin-user-id', 'Eccles Cakes', 'British Dessert dish', 'To make the pastry, dice the butter and put it in the freezer to go really hard. Tip flour into the bowl of a food processor with half the butter and pulse to the texture of breadcrumbs. Pour in the lemon juice and 100ml iced water, and pulse to a dough. Tip in the rest of the butter and pulse a few times until the dough is heavily flecked with butter. It is important that you don’t overdo this as the flecks of butter are what makes the pastry flaky.
